const raw = $input.first().json.content[0].text.trim();
let parsed;
try {
  let cleaned = raw.replace(/```json\n?/gi,'').replace(/```\n?/gi,'').trim();
  let depth = 0, start = -1, end = -1;
  for (let i = 0; i < cleaned.length; i++) {
    if (cleaned[i] === '{') { if (depth === 0) start = i; depth++; }
    else if (cleaned[i] === '}') { depth--; if (depth === 0) { end = i; break; } }
  }
  if (start === -1 || end === -1) throw new Error('No valid JSON object found');
  parsed = JSON.parse(cleaned.substring(start, end + 1));
} catch(err) {
  parsed = { analysis: raw, questions: [], suggestions: [], ready_to_generate: false };
}
return [{ json: { phase: 'clarify', ...parsed } }];

const raw = $input.first().json.content[0].text.trim();
let workflowJson = null;
let parseError = null;
let auditErrors = [];
let auditWarnings = [];
try {
  let cleaned = raw.replace(/```json\n?/gi,'').replace(/```\n?/gi,'').trim();
  let depth = 0, start = -1, end = -1;
  for (let i = 0; i < cleaned.length; i++) {
    if (cleaned[i] === '{') { if (depth === 0) start = i; depth++; }
    else if (cleaned[i] === '}') { depth--; if (depth === 0) { end = i; break; } }
  }
  if (start === -1 || end === -1) throw new Error('No valid JSON object found');
  const parsed = JSON.parse(cleaned.substring(start, end + 1));
  workflowJson = parsed.workflow || parsed;
  auditErrors = parsed.errors || [];
  auditWarnings = parsed.warnings || [];
  if(!workflowJson.name || !Array.isArray(workflowJson.nodes) || !workflowJson.connections || !workflowJson.settings) throw new Error('Structure invalide');
} catch(err) {
  parseError = err.message;
  workflowJson = null;
}
return [{ json: { workflowJson, parseError, isValid: workflowJson !== null, auditErrors, auditWarnings } }];

// Sanitise typeVersions pour compatibilite n8n
const input = $input.first().json;
if (!input.workflowJson || !input.isValid) return [{ json: input }];

const MAX_VERSIONS = {
  'n8n-nodes-base.set': 3.3,
  'n8n-nodes-base.httpRequest': 4.2,
  'n8n-nodes-base.if': 2,
  'n8n-nodes-base.code': 2,
  'n8n-nodes-base.webhook': 2,
  'n8n-nodes-base.googleSheets': 4.2,
  'n8n-nodes-base.gmail': 2.1,
  'n8n-nodes-base.telegram': 1.1,
  'n8n-nodes-base.scheduleTrigger': 1.1,
  'n8n-nodes-base.manualTrigger': 1,
  'n8n-nodes-base.respondToWebhook': 1.1,
  'n8n-nodes-base.splitInBatches': 3,
  'n8n-nodes-base.googleDrive': 3,
  'n8n-nodes-base.extractFromFile': 1,
  'n8n-nodes-base.formTrigger': 1,
  'n8n-nodes-base.formResponse': 1,
  'n8n-nodes-base.spreadsheetFile': 2,
  'n8n-nodes-base.readBinaryFile': 1,
  'n8n-nodes-base.writeBinaryFile': 1,
  'n8n-nodes-base.merge': 2.1,
  'n8n-nodes-base.switch': 3,
  'n8n-nodes-base.filter': 1,
  'n8n-nodes-base.aggregate': 1,
  'n8n-nodes-base.limit': 1
};

input.workflowJson.nodes = input.workflowJson.nodes.map(n => {
  const max = MAX_VERSIONS[n.type];
  if (max && n.typeVersion > max) {
    n.typeVersion = max;
  } else if (!max && n.typeVersion > 2) {
    // Nodes inconnus : force typeVersion 1 si > 2
    n.typeVersion = 1;
  }
  return n;
});

return [{ json: input }];

const wf = $input.first().json;
const auditErrors = $('Sanitiser typeVersions').first().json.auditErrors || [];
const auditWarnings = $('Sanitiser typeVersions').first().json.auditWarnings || [];

let nodes = [...wf.nodes];
let connections = JSON.parse(JSON.stringify(wf.connections));

const triggerTypes = ['Trigger','webhook','schedule','cron','interval','manualTrigger'];
const firstTrigger = wf.nodes.find(n =>
  triggerTypes.some(t => n.type.toLowerCase().includes(t.toLowerCase()))
);
const triggerName = firstTrigger ? firstTrigger.name : null;
const firstTarget = triggerName && connections[triggerName]
  ? connections[triggerName].main[0][0].node : null;

const hasManualTrigger = wf.nodes.some(n => n.type === 'n8n-nodes-base.manualTrigger');
if (!hasManualTrigger) {
  const posX = firstTrigger ? firstTrigger.position[0] : 250;
  const posY = firstTrigger ? firstTrigger.position[1] - 120 : 180;
  nodes = [{ id: 'manual-trigger-auto', name: 'Manual Trigger', type: 'n8n-nodes-base.manualTrigger', typeVersion: 1, position: [posX, posY], parameters: {} }, ...nodes];
  if (firstTarget) connections['Manual Trigger'] = { main: [[{ node: firstTarget, type: 'main', index: 0 }]] };
}

const webhookPath = 'run-' + wf.id;

// Detecte le vrai chemin webhook principal (pas le run trigger)
const realWebhookNode = wf.nodes.find(n =>
  n.type === 'n8n-nodes-base.webhook' &&
  n.name !== 'WORKFLOW-AUTO Run Trigger' &&
  n.parameters && n.parameters.path
);
const realWebhookPath = realWebhookNode ? realWebhookNode.parameters.path : null;
const hasRunTrigger = wf.nodes.some(n => n.name === 'WORKFLOW-AUTO Run Trigger');
if (!hasRunTrigger && firstTarget) {
  const posX = firstTrigger ? firstTrigger.position[0] : 250;
  const posY = firstTrigger ? firstTrigger.position[1] - 240 : 60;
  nodes = [{
    id: 'aegis-run-trigger',
    name: 'WORKFLOW-AUTO Run Trigger',
    type: 'n8n-nodes-base.webhook',
    typeVersion: 2,
    position: [posX, posY],
    parameters: { httpMethod: 'POST', path: webhookPath, responseMode: 'onReceived', options: {} }
  }, ...nodes];
  connections['WORKFLOW-AUTO Run Trigger'] = { main: [[{ node: firstTarget, type: 'main', index: 0 }]] };
  auditWarnings.push('Webhook WORKFLOW-AUTO injecte : POST /webhook/' + webhookPath);
}

// Analyse du workflow pour générer testPayload et uiSpec
const webhookNode = wf.nodes.find(n => n.type === 'n8n-nodes-base.webhook' && n.name !== 'WORKFLOW-AUTO Run Trigger');
const scheduleNode = wf.nodes.find(n => n.type === 'n8n-nodes-base.scheduleTrigger');

// Détecter les champs attendus depuis les nodes Code
let detectedFields = [];
let testPayload = {};
let uiSpec = { needed: false, fields: [], title: wf.name, description: '' };

// Scan tous les nodes Code pour trouver les champs référencés
wf.nodes.forEach(n => {
  if (n.type === 'n8n-nodes-base.code' && n.parameters && n.parameters.jsCode) {
    const code = n.parameters.jsCode;
    // Cherche patterns comme $json.prenom, body.email, $json['nom'], json.message
    const matches = code.match(/\$json\.([a-zA-Z_][a-zA-Z0-9_]*)/g) || [];
    const matches2 = code.match(/body\.([a-zA-Z_][a-zA-Z0-9_]*)/g) || [];
    const matches3 = code.match(/\$json\['([^']+)'\]/g) || [];
    [...matches, ...matches2, ...matches3].forEach(m => {
      const field = m.replace(/\$json\.|body\.|\$json\[|'|\]/g, '');
      if (!['source', 'headers', 'query', 'body', 'params'].includes(field) && !detectedFields.includes(field)) {
        detectedFields.push(field);
      }
    });
  }
  // Scan aussi les expressions dans les autres nodes
  if (n.parameters) {
    JSON.stringify(n.parameters).match(/\$json\.([a-zA-Z_][a-zA-Z0-9_]*)/g)?.forEach(m => {
      const field = m.replace('$json.', '');
      if (!['source', 'id', 'name', 'type'].includes(field) && !detectedFields.includes(field)) {
        detectedFields.push(field);
      }
    });
  }
});

// Génère testPayload et uiSpec depuis les champs détectés
if (detectedFields.length > 0) {
  detectedFields.forEach(field => {
    const lower = field.toLowerCase();
    if (lower.includes('email')) { testPayload[field] = 'test@example.com'; }
    else if (lower.includes('nom') || lower.includes('prenom') || lower.includes('name')) { testPayload[field] = 'Jean Dupont'; }
    else if (lower.includes('tel') || lower.includes('phone')) { testPayload[field] = '+33612345678'; }
    else if (lower.includes('date')) { testPayload[field] = new Date().toISOString().slice(0,10); }
    else if (lower.includes('montant') || lower.includes('prix') || lower.includes('amount')) { testPayload[field] = 100; }
    else if (lower.includes('message') || lower.includes('texte') || lower.includes('text') || lower.includes('instruction')) { testPayload[field] = 'Ceci est un test'; }
    else if (lower.includes('id')) { testPayload[field] = '12345'; }
    else { testPayload[field] = 'valeur_test'; }

    // UI field type detection
    const isTextarea = lower.includes('message') || lower.includes('texte') || lower.includes('description') || lower.includes('instruction');
    const isEmail = lower.includes('email');
    const isFile = lower.includes('file') || lower.includes('fichier') || lower.includes('document');
    uiSpec.fields.push({
      name: field,
      label: field.charAt(0).toUpperCase() + field.slice(1).replace(/_/g, ' '),
      type: isFile ? 'file' : isEmail ? 'email' : isTextarea ? 'textarea' : 'text',
      placeholder: 'Entrez ' + field,
      required: true
    });
  });
  uiSpec.needed = webhookNode ? true : false;
  uiSpec.description = 'Interface pour ' + wf.name;
}

// Si workflow schedule (pas de webhook), pas d'UI nécessaire
if (scheduleNode && !webhookNode) {
  uiSpec.needed = false;
  testPayload = {};
}

return [{
  json: {
    workflowId: wf.id,
    workflowName: wf.name,
    webhookPath,
    realWebhookPath,
    auditErrors,
    auditWarnings,
    testPayload,
    uiSpec,
    putBody: {
      name: wf.name,
      nodes,
      connections,
      settings: { executionOrder: 'v1', errorWorkflow: 'YOUR_N8N_URL/workflow/RaHgXr2IpKEIfpw1' }
    }
  }
}];

