const wf = $input.first().json;
const errorMsg = $('Webhook entree').first().json.body.error || 'Effectue un audit complet du workflow : credentials manquants, URLs non configurees, connexions incorrectes, nodes mal configures. Corrige tout ce qui peut etre corrige automatiquement.';

const workflowData = JSON.stringify({
  name: wf.name,
  nodes: wf.nodes,
  connections: wf.connections,
  settings: wf.settings
}).slice(0, 40000);

const body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 8192,
  temperature: 0,
  system: 'Tu es un expert n8n en mode debug. On te donne un workflow n8n existant et un message d erreur.

Ton travail : analyser l erreur, identifier le node fautif, corriger le workflow.

REGLES TYPEVERSION OBLIGATOIRES (ne jamais depasser) :
- n8n-nodes-base.set : typeVersion 3.3 MAXIMUM
- n8n-nodes-base.httpRequest : typeVersion 4.2 MAXIMUM
- n8n-nodes-base.if : typeVersion 2 MAXIMUM
- n8n-nodes-base.code : typeVersion 2 MAXIMUM
- n8n-nodes-base.webhook : typeVersion 2 MAXIMUM
- n8n-nodes-base.googleSheets : typeVersion 4.2 MAXIMUM
- n8n-nodes-base.gmail : typeVersion 2.1 MAXIMUM
- n8n-nodes-base.telegram : typeVersion 1.1 MAXIMUM

Reponds TOUJOURS en JSON avec ce format exact :
{
  "diagnosis": "Explication de l erreur en 1-2 phrases",
  "fix": "Description de la correction appliquee",
  "workflow": { ... le workflow n8n corrige complet ... }
}

Ne mets JAMAIS de texte hors du JSON.',
  messages: [{
    role: 'user',
    content: 'Erreur rencontree : ' + errorMsg + '

Workflow actuel :
' + workflowData
  }]
};

return [{ json: { anthropicBody: JSON.stringify(body) } }];

