    workflowId,
    diagnosis: input.diagnosis,
    fix: input.fix,
    webhookPath,
    putBody: {
      name: wf.name,
      nodes,
      connections,
      settings: { executionOrder: 'v1', errorWorkflow: 'YOUR_N8N_URL/workflow/RaHgXr2IpKEIfpw1' }
    }
  }
}];

const body = $('Webhook entree').first().json.body;
const wfId = body.workflowId || '';
const webhookUrl = body.webhookUrl || '';
const users = body.users || 'grand public';
const inputs = body.inputs || 'formulaire';
const output = body.output || 'message de confirmation';
const style = body.style || 'minimal';
const extra = body.extra || '';
const hasFile = /fichier|file|excel|pdf|upload/i.test(inputs);

const prompt = [
  'Genere une interface HTML complete, autonome et moderne.',
  '',
  'WEBHOOK CIBLE : POST ' + webhookUrl,
