  '3. Spinner pendant appel, afficher resultat JSON apres',
  '4. Gestion erreurs reseau',
  '5. Design responsive professionnel',
  '6. Reponds UNIQUEMENT avec le code HTML complet'
].filter(Boolean).join('\n');

const body2 = {
  model: 'claude-sonnet-4-6',
  max_tokens: 8000,
  temperature: 0,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { anthropicBody: JSON.stringify(body2), workflowId: wfId } }];
